  "inlineSchema": "generator client {\n  provider = \"prisma-client-js\"\n}\n\ndatasource db {\n  provider = \"sqlite\"\n  url      = env(\"DATABASE_URL\")\n}\n\nmodel Ensemble {\n  id          String   @id @default(uuid())\n  name        String\n  createdAt   DateTime @default(now())\n  updatedAt   DateTime @updatedAt\n  conductorId String\n\n  scores     Score[]\n  rehearsals Rehearsal[]\n  members    Member[]\n}\n\nmodel Member {\n  id         String   @id @default(uuid())\n  name       String\n  role       String // CONDUCTOR or PLAYER\n  instrument String?\n  section    String? // 声部，如 \"violin\", \"cello\", \"flute\"\n  ensembleId String\n  ensemble   Ensemble @relation(fields: [ensembleId], references: [id], onDelete: Cascade)\n\n  marks     Mark[]\n  createdAt DateTime @default(now())\n}\n\nmodel Score {\n  id         String   @id @default(uuid())\n  title      String\n  composer   String?\n  fileUrl    String // PDF 或 MusicXML 文件路径\n  fileType   String // \"pdf\" | \"musicxml\"\n  audioUrl   String? // 参考音频\n  ensembleId String\n  ensemble   Ensemble @relation(fields: [ensembleId], references: [id], onDelete: Cascade)\n\n  measures  Measure[]\n  marks     Mark[]\n  createdAt DateTime  @default(now())\n  updatedAt DateTime  @updatedAt\n}\n\nmodel Measure {\n  id      String @id @default(uuid())\n  number  Int // 小节号\n  scoreId String\n  score   Score  @relation(fields: [scoreId], references: [id], onDelete: Cascade)\n\n  startTime Float? // 音频中的起始时间（秒）\n  endTime   Float? // 音频中的结束时间（秒）\n\n  cues Cue[]\n}\n\nmodel Mark {\n  id            String   @id @default(uuid())\n  type          String // DRAWING, TEXT, HIGHLIGHT\n  data          String // JSON 序列化的标记数据\n  x             Float\n  y             Float\n  width         Float?\n  height        Float?\n  page          Int // 乐谱页码\n  measureId     String?\n  scoreId       String\n  score         Score    @relation(fields: [scoreId], references: [id], onDelete: Cascade)\n  creatorId     String\n  creator       Member   @relation(fields: [creatorId], references: [id])\n  targetSection String? // 目标声部，null表示全体\n  createdAt     DateTime @default(now())\n  updatedAt     DateTime @updatedAt\n}\n\nmodel Cue {\n  id            String   @id @default(uuid())\n  type          String // CLICK, COUNT_IN, METRONOME, DEMO_AUDIO\n  measureId     String\n  measure       Measure  @relation(fields: [measureId], references: [id], onDelete: Cascade)\n  targetSection String? // 目标声部\n  audioUrl      String? // 提示音音频\n  bpm           Int? // 节拍器速度\n  timeSignature String? // 拍号\n  createdAt     DateTime @default(now())\n}\n\nmodel Rehearsal {\n  id           String    @id @default(uuid())\n  ensembleId   String\n  ensemble     Ensemble  @relation(fields: [ensembleId], references: [id], onDelete: Cascade)\n  scoreId      String?\n  startedAt    DateTime  @default(now())\n  endedAt      DateTime?\n  recordingUrl String? // 排练录音文件\n\n  events RehearsalEvent[]\n}\n\nmodel RehearsalEvent {\n  id          String    @id @default(uuid())\n  rehearsalId String\n  rehearsal   Rehearsal @relation(fields: [rehearsalId], references: [id], onDelete: Cascade)\n  type        String // MARK_ADDED, CUE_SENT, SECTION_PLAYING, MISTAKE_DETECTED\n  data        String // JSON 事件数据\n  timestamp   DateTime  @default(now())\n}\n\n// Enums removed - using String types for SQLite compatibility\n",
